const Btn = ({ children, v = "primary", t, ...p }) => <button {...p} style={{ padding: "10px 18px", borderRadius: 8, border: "none", background: v === "primary" ? GO : v === "danger" ? RD : t.btnGhost, color: v === "primary" ? "#0A1628" : v === "danger" ? "#F8F7F4" : t.text, fontSize: 13, fontWeight: 700, cursor: "pointer", ...p.style }}>{children}</button>;
